      "content": ":root {
    --primary-color: #f97316;
    --secondary-color: #475569;
    --background-color: #0f172a;
    --text-color: #f8fafc;
    --accent-color: #6b7280;
    --success-color: #10b981;
    --error-color: #ef4444;
    --font-family: 'Inter', system-ui, sans-serif;
    --transition-duration: 0.3s;
}

* {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

body {
    font-family: var(--font-family);
    color: var(--text-color);
    background-color: var(--background-color);
    line-height: 1.6;
    overflow-x: hidden;
}

#root {
    display: flex;
    flex-direction: column;
    min-height: 100vh;
}

/* Header & Navigation */
.header {
    background: var(--background-color);
    border-bottom: 2px solid var(--primary-color);
    position: sticky;
    top: 0;
    z-index: 100;
}

.nav {
    max-width: 1200px;
    margin: 0 auto;
    padding: 1rem 2rem;
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.nav-brand h1 {
    color: var(--primary-color);
    font-size: 1.8rem;
    font-weight: 700;
}

.nav-menu {
    display: flex;
    list-style: none;
    gap: 2rem;
}

.nav-link {
    color: var(--text-color);
    text-decoration: none;
    font-weight: 500;
    transition: color var(--transition-duration);
    position: relative;
}

.nav-link:hover,
.nav-link.active {
    color: var(--primary-color);
}

.nav-link.active::after {
    content: '';
    position: absolute;
    bottom: -5px;
    left: 0;
    width: 100%;
    height: 2px;
    background: var(--primary-color);
}

/* Hero Section */
.hero {
    padding: 6rem 2rem;
    text-align: center;
    background: linear-gradient(135deg, #0f172a 0%, #1e293b 100%);
    position: relative;
    overflow: hidden;
}

.hero::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: url('data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100"><defs><pattern id="grid" width="10" height="10" patternUnits="userSpaceOnUse"><path d="M 10 0 L 0 0 0 10" fill="none" stroke="rgba(79, 70, 92, 0.1)" stroke-width="0.5"/></pattern></defs><rect width="100" height="100" fill="url(%23grid)"/></svg>');
    opacity: 0.3;
}

.hero-content {
    position: relative;
    z-index: 1;
}

.hero-title {
    font-size: 4rem;
    font-weight: 800;
    margin-bottom: 1rem;
    background: linear-gradient(135deg, var(--primary-color), var(--text-color));
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

.hero-subtitle {
    font-size: 1.5rem;
    color: var(--secondary-color);
    margin-bottom: 2rem;
}

.countdown-container {
    margin-bottom: 2rem;
}

.countdown-container h3 {
    color: var(--primary-color);
    margin-bottom: 1rem;
    font-size: 1.2rem;
    font-weight: 600;
}

.countdown {
    display: flex;
    justify-content: center;
    gap: 1.5rem;
    flex-wrap: wrap;
}

.countdown-item {
    background: rgba(79, 70, 92, 0.3);
    backdrop-filter: blur(10px);
    border: 1px solid rgba(79, 70, 92, 0.5);
    border-radius: 12px;
    padding: 1rem;
    text-align: center;
    min-width: 80px;
    transition: all var(--transition-duration);
}

.countdown-item:hover {
    background: rgba(79, 70, 92, 0.5);
    transform: translateY(-2px);
}

.countdown-number {
    display: block;
    font-size: 2rem;
    font-weight: 700;
    color: var(--primary-color);
}

.countdown-label {
    font-size: 0.8rem;
    color: var(--secondary-color);
    text-transform: uppercase;
    letter-spacing: 1px;
}

.hero-description {
    font-size: 1.1rem;
    color: var(--secondary-color);
    max-width: 600px;
    margin: 0 auto;
}

/* Products Page */
.products-header {
    padding: 4rem 2rem;
    text-align: center;
    background: linear-gradient(135deg, #1e293b 0%, #0f172a 100%);
}

.products-header h1 {
    font-size: 3rem;
    margin-bottom: 1rem;
    color: var(--primary-color);
}

.products-header p {
    color: var(--secondary-color);
    font-size: 1.2rem;
}

.product-grid {
    padding: 4rem 2rem;
    background: var(--background-color);
}

.container {
    max-width: 1200px;
    margin: 0 auto;
}

.product-card {
    background: rgba(79, 70, 92, 0.1);
    backdrop-filter: blur(10px);
    border: 1px solid rgba(79, 70, 92, 0.3);
    border-radius: 16px;
    overflow: hidden;
    transition: all var(--transition-duration);
    margin-bottom: 2rem;
}

.product-card:hover {
    transform: translateY(-5px);
    box-shadow: 0 20px 40px rgba(0, 0, 0, 0.3);
}

.product-image {
    height: 300px;
    overflow: hidden;
}

.product-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.product-info {
    padding: 2rem;
}

.product-info h3 {
    color: var(--primary-color);
    margin-bottom: 0.5rem;
    font-size: 1.5rem;
}

.product-price {
    color: var(--success-color);
    font-size: 1.3rem;
    font-weight: 600;
    margin-bottom: 1rem;
}

.product-description {
    color: var(--secondary-color);
    margin-bottom: 1.5rem;
}

.product-link {
    display: inline-block;
    color: var(--primary-color);
    text-decoration: none;
    font-weight: 500;
    padding: 0.5rem 1rem;
    border: 1px solid var(--primary-color);
    border-radius: 8px;
    transition: all var(--transition-duration);
}

.product-link:hover {
    background: var(--primary-color);
    color: var(--background-color);
}

/* Contact Form */
.contact-header {
    padding: 4rem 2rem;
    text-align: center;
    background: linear-gradient(135deg, #1e293b 0%, #0f172a 100%);
}

.contact-header h1 {
    font-size: 3rem;
    margin-bottom: 1rem;
    color: var(--primary-color);
}

.contact-header p {
    color: var(--secondary-color);
    font-size: 1.2rem;
}

.contact-form-section {
    padding: 4rem 2rem;
    background: var(--background-color);
}

.contact-form {
    max-width: 600px;
    margin: 0 auto;
    background: rgba(79, 70, 92, 0.1);
    backdrop-filter: blur(10px);
    border: 1px solid rgba(79, 70, 92, 0.3);
    border-radius: 16px;
    padding: 3rem;
}

.contact-form h2 {
    color: var(--primary-color);
    margin-bottom: 2rem;
    font-size: 2rem;
    text-align: center;
}

.form-group {
    margin-bottom: 1.5rem;
}

.form-group label {
